import React from 'react';
import styles from './mega-menu.module.css';

interface MegaMenuProps {
  dropDownItems: string[]; // Update the type to match your data structure
  show: boolean;
}

const MegaMenu: React.FC<MegaMenuProps> = ({ dropDownItems, show }) => {
  return (
    <div className={`${styles.megMenu__container} ${show ? styles.show : ''}`}>
      <div className="container">
        <ul className={`${styles.megaMenu__content} ${styles.listContainer}`}>
          {dropDownItems.map((item, index) => (
            <li key={index}>{item}</li>
          ))}
        </ul>
      </div>
    </div>
  );
}

export default MegaMenu;
